import React, { useState, useEffect } from 'react';
import axios from 'axios';

const EventEditComponent = ({ eventId }) => {
  const [event, setEvent] = useState({
    event_id: eventId,
    event_name: '',
    event_state: ''
  });

  useEffect(() => {
    // コンポーネントのマウント時にイベントデータを取得
    axios.get(`/event/get?event_id=${eventId}`)
      .then(response => {
        // 取得したイベントデータで状態を更新
        setEvent({
          event_id: eventId,
          event_name: response.data.event_name,
          event_state: response.data.event_state
        });
      })
      .catch(error => {
        console.error('イベントの取得に失敗しました。', error);
      });
  }, [eventId]);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setEvent(prevState => ({
      ...prevState,
      [name]: value
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    axios.put('/event/edit', event)
      .then(response => {
        console.log('イベントが更新されました。', response.data);
        // 必要であれば、更新後の処理をここに記述
      })
      .catch(error => {
        console.error('イベントの更新に失敗しました。', error);
      });
  };

  return (
    <div>
      <h2>イベント編集画面</h2>
      <form onSubmit={handleSubmit}>
        <div>
          <label>イベント名：</label>
          <input
            type="text"
            name="event_name"
            value={event.event_name}
            onChange={handleInputChange}
          />
        </div>
        <div>
          <label>イベント状態：</label>
          <select
            name="event_state"
            value={event.event_state}
            onChange={handleInputChange}
          >
            <option value="draft">下書き</option>
            <option value="open">公開中</option>
            <option value="close">終了</option>
          </select>
        </div>
        <button type="submit">更新</button>
      </form>
    </div>
  );
};

export default EventEditComponent;
